@ARTICLE{10.1109/tpwrd.2015.2500260,
	author = {Wang, Ying and Liu, Zhi Gang and Mu, Xiu Qing and Huang, Ke and Wang, Hong Rui and Gao, Shi Bin},
	title = {An Extended Habedank’s Equation-Based EMTP Model of Pantograph Arcing Considering Pantograph-Catenary Interactions and Train Speeds},
	journal = {IEEE Transactions on Power Delivery},
	year = {2016},
	keywords = {Arc parameters; Electromagnetic Transients Program (EMTP); EMTP; Finite element analysis; finite-element method (FEM); high-speed railway (HSR); Load modeling; Mathematical model; pantograph arcing; Rail transportation; Suspensions; Wires ER -},
	abstract = {Pantograph arcing is a more and more common and prominent phenomenon in ac-electrified railway systems, especially with the increase of pantograph-catenary (PAC) interaction and train speed. In order to address this issue, an extended Habedank’s equation-based model, by means of the Electromagnetic Transients Program (EMTP), is presented to obtain equivalent modeling for pantograph arcing studies considering train speeds in this paper. First, the pantograph arcing phenomenon is investigated, such as transient mechanisms and influencing factors. Second, based on the features of existing and emerging pantograph arcing, Habedank’s arc equations are further derived and studied by improving voltage gradient and power dissipation. Next, due to the relationship among voltage gradient, power dissipation, and arc length, the maximum detachment interval law between pantograph and contact wire is obtained by establishing the finite-element model for PAC interaction, and the ultimate extended Habedank’s equation-based EMTP model of pantograph arcing considering different train speeds is acquired. Then, the related model parameters are discussed and determined. Finally, based on the China Beijing-Yizhuang HSR line model in EMTP, the arc characteristic differences considering loads under different parameter values are compared and analyzed. The comparison results illustrate that the proposed model can be feasible to determine and reveal the pantograph arcing characteristics and influences in the HSR system as well as the PAC contact loss problems.},
	doi = {10.1109/tpwrd.2015.2500260},
	type = {JOUR}
}

@ARTICLE{10.3390/app14166861,
	author = {Jiang, Da Zuo and Zou, Huan Qing and Guo, Yi Ke and Tian, Fu Qiang and Liu, Hong Qi and Yin, Yu Feng},
	title = {Simulation on Operating Overvoltage of Dropping Pantograph Based on Pantograph–Catenary Arc and Variable Capacitance Model},
	journal = {Applied Sciences},
	year = {2024},
	keywords = {arc model; electromagnetic oscillation; operating overvoltage of dropping pantograph; variable capacitance ER -},
	abstract = {When the electric locomotive pantograph is dropping, the interruption of pantograph catenary contact causes electromagnetic oscillation and arcing. The frequent arc burning that occurs due to charge accumulation results in the amplitude of overvoltage increasing gradually, posing a threat to locomotive high-voltage equipment. However, the physical mechanisms and characteristics of overvoltage are still unclear. This paper proposes a simulation model of operating overvoltage due to a dropping pantograph based on the pantograph–catenary arc and variable capacitance. Distributed RLC electromagnetic oscillation is considered, which allows the real-time calculation of arc resistance and capacitance. Under the same working conditions, the error between the simulation and test results is less than 4.0%, which proves the credibility of the model. The variation law of overvoltage under different dropping speeds or catenary phases was investigated, which shows the max amplitude is 298.20 kV and steepness is 2096.80 kV/μs at 0.30 m/s speed. The waveform shows the characteristics of high amplitude and high steepness, similar to very fast transient overvoltage (VFTO). There is a sinusoidal relationship between the catenary phase and overvoltage amplitude. The closer the catenary phase to 90°, the higher the overvoltage amplitude. The research has important guiding significance for the overvoltage formation mechanism of a traction power supply system and the insulation coordination design of high-voltage equipment.},
	doi = {10.3390/app14166861},
	type = {JOUR}
}

@ARTICLE{10.1109/tps.2025.3558860,
	author = {Zou, Dan Dan and Xin Xia, Zi and Tian Xu, Guang and Sarkar, Sanjib and Atul, Jyoti K. and Fen Shi, Gui and Yao Wang, Meng},
	title = {Influence of Low Air Pressure on Pantograph–Catenary Arc Model},
	journal = {IEEE Transactions on Plasma Science},
	year = {2025},
	keywords = {Atmospheric modeling; Closed box; Convection; Heating systems; High-altitude; Integrated circuit modeling; Mathematical models; Mayr arc model; pantograph-catenary arc; Schwarz arc model; Temperature; Voltage measurement ER -},
	abstract = {The pantograph-catenary arc is a crucial factor that significantly impacts the effective current collection of high-speed railway pantograph-catenary systems. Investigating the electrical properties of this arc has engineering applications for enhancing the reliability and operational lifespan of such systems. The electrical characteristics of the pantograph-catenary arc in high-altitude areas with low gas pressure differ from those in low-altitude areas with atmospheric pressure across various aspects. In this article, we model the pantograph-catenary arc based on both Mayr arc and Schwarz arc mathematical models. By adjusting the dissipation power value, we investigate the arc voltage-time, arc conductance-time, and arc power-time characteristic curves under different altitudes, and establish the mechanism of low gas pressure on pantograph-catenary arc. A comparison between simulation results obtained using these two models reveals that Schwarz’s model is more suitable for modeling high-altitude pantograph-catenary arcs. The results indicate that, throughout the arcing process, the arc conductance of the pantograph-catenary system significantly decreases with increasing altitude, while the arc quenching capability of the pantograph-catenary system synchronously increases with altitude. This finding provides valuable insights for designing parameters related to pantograph-catenary systems in high-altitude regions worldwide.},
	doi = {10.1109/tps.2025.3558860},
	type = {JOUR}
}

@ARTICLE{10.1016/j.epsr.2025.112665,
	author = {Huang, Gui Zao and Ma, Tong Xin and Liu, Yu Xin and Li, Zheng and Gao, Guo Qiang and Wu, Guang Ning},
	title = {Effect of ice coating on thermal characteristics of pantograph-catenary arc and power quality of traction drive system},
	journal = {Electric Power Systems Research},
	year = {2026},
	keywords = {Arc; Ice coating; Pantograph-catenary system; Power quality; Thermal characteristics ER -},
	abstract = {The contact between pantograph and catenary lines with current flow is the sole means through which high-speed trains obtain electrical energy. The catenary system is prone to ice accretion in cold environments, which can induce severe vibrations and pantograph–catenary detachment. The resulting arcing not only produces substantial heat that accelerates the erosion of both the pantograph strip and the contact wire, but also exerts a significant adverse influence on the power quality of the traction drive system. In this study, a novel model combined with pantograph-catenary dynamic model, arc model as well as an equivalent model of the traction drive system is established to investigate the thermal characteristics of offline arcs caused by ice accretion and its impact on the power quality of traction drive system. The results indicate that more severe icing conditions lead to stronger offline arcing and consequently more pronounced erosion of the pantograph–catenary system. Moreover, overvoltage and harmonic distortion caused by the arcing further deteriorate the electrical energy quality. Under extreme conditions, the total harmonic distortion (THD) at the onboard transformer can reach up to 15 %, posing a significant threat to the safe operation of the train. This study provides the first insight into pantograph–catenary arcing under icing conditions and its influence on the traction system, offering valuable guidance for ensuring the safe and reliable operation of high-speed rail systems.},
	doi = {10.1016/j.epsr.2025.112665},
	type = {JOUR}
}

@ARTICLE{10.1177/0954409717747754,
	author = {Gao, Guo Qiang and Zhang, Ting Ting and Wei, Wen Fu and Hu, Yi and Wu, Guang Ning and Zhou, Ning},
	title = {A pantograph arcing model for electrified railways with different speeds},
	journal = {Proceedings of the Institution of Mechanical Engineers, Part F: Journal of Rail and Rapid Transit},
	year = {2018},
	abstract = {Pantograph arcing is an unavoidable phenomenon in electrified railways, which not only causes damage to the carbon strip and the catenary contact line but also results in voltage surge and electromagnetic interference. In recent years, there are more cases of pantograph arcing due to the increase in speed of trains. Therefore, it is essential to understand the basic electrical characteristics of pantograph arcing at different running speeds of trains. In this work, a pantograph arcing model was proposed, which considers the effects of the speed of a train on the arc-dissipated power. An overall electrical model, concerning the traction power system and the traction drive system, was further established. The results indicated that the running speed of trains significantly influenced the arcing voltage, duration of arcing, and the zero-crossing time. A qualitative relation between the average power of the arc and the speed of the train was also presented. Finally, field tests were carried out, and comparisons between the field testing data and the calculated results were made, which validate the accuracy of the developed model. ER -},
	doi = {10.1177/0954409717747754},
	type = {JOUR}
}

@ARTICLE{10.13052/2023.aces.j.380205,
	author = {Tang, Yu Tao and Li, Fei and Zhou, Chao and Wang, Yu Lin and Zhu, Feng},
	title = {Research on the Model and Transient Characteristics of the Pantograph-Catenary Arc in Different Sections of Power Supply Lines},
	journal = {The Applied Computational Electromagnetics Society Journal (ACES)},
	year = {2023},
	keywords = {pantograph-catenary arc ER -},
	abstract = {During the operation of high-speed trains, the pantograph will inevitably have occasional and instantaneous separations from the power supply line, resulting in the pantograph catenary arc (PCA). The diverse states of PCA generated in different sections of the power supply line will lead to various electromagnetic interference (EMI). To study the transient characteristics of PCA, firstly, the voltage and the dissipative power of PCA at the common and neutral sections of the power supply line are analyzed and calculated respectively. Secondly, two PCA models that describe the different PCA states are established based on the improved Habedank arc model. Finally, the high-frequency transient voltage and current of the PCA when high-speed trains pass through the common and neutral sections at different speeds are obtained by simulation. In this paper, we comprehensively study the model and the transient characteristics of PCA, which provides a theoretical basis and relevant data for further study of its EMI.},
	doi = {10.13052/2023.aces.j.380205},
	type = {JOUR}
}

@ARTICLE{10.1109/access.2024.3502393,
	author = {Pan, Li Ke and Wang, Hong Chi and Yu, Zhi Qiang and Xing, Tong and Yang, Cai Zhi and Yuan, Yuan and Zhu, Xiao Han and Sun, Jian Xiang and Sun, Xiao Yun and Cui, Yue Hua and Feng, Tao and Yi, Xu Dong and Chen, Jian Hua and Yan, Wen Xia},
	title = {Electrical Characterization of Pantograph and Catenary Offline Under Train Operating Conditions Based on Improved Habedank Model and AT Power Supply Network},
	journal = {IEEE Access},
	year = {2024},
	keywords = {arc model; Discharges (electric); distribution parameter modeling; Electric variables; fully parallel AT power supply; High-speed rail; Immune system; Integrated circuit modeling; Mathematical models; off-line of pantograph and catenary; Picture archiving and communication systems; Power supplies; Substations; Voltage; Wire ER -},
	abstract = {Presently, with the increase in the operating speed of a train, the off-line phenomenon of its pantograph and the contact wire occurs intermittently, which affects the quality of its receiving current. In this paper, a distributed parameter-based Habedank arc model for a fully parallel AT power supply network is developed to examine the electrical characteristics under the typical operating conditions, including the normal travel and entry/exit stations. The incorporation of the train acceleration parameter facilitates further enhancement of the Habedank arc model and the equivalent dynamic resistance, also validating them. The results show that the off-line discharge arc voltage of the train pantograph and the locomotive voltage waveform during the overcurrent phase separation interval show a decreasing and increasing trend respectively when entering and leaving the station. Due to the nonlinear dynamic characteristics of the arc, the overall waveform contains many harmonics. The advantage of this model is that it is a simple, rapid, and highly accurate method for constructing an off-line discharge circuit model of the pantograph and catenary (PAC) under the working conditions. This paper introduces a novel approach to studying the electrical characteristics of the PAC discharge model with distributed parameters in a fully parallel AT power supply network. Also, it considers the effects of the operational conditions of the train, such as the entering and leaving stations, on the discharge characteristics. The research results of this paper can provide a reference for the identification of the electrical characteristics and protection of a PAC equipment during the operation of the train under the working conditions.},
	doi = {10.1109/access.2024.3502393},
	type = {JOUR}
}

@ARTICLE{10.3390/en17163883,
	author = {Pan, Li Ke and Xie, Biao Huan and Chen, Li Ming and Xing, Tong and Zhang, Hai Bo and Lu, Yan Ming and Song, Yang},
	title = {Study on the Influencing Factors of Electrical Characteristics of Articulated Split-Zone Insulator Arc},
	journal = {Energies},
	year = {2024},
	keywords = {arc modeling; articulated split-zone insulator; high-speed railway; pantograph–catenary arcing ER -},
	abstract = {The frequent occurrence of the pantograph–catenary (PC) arc seriously threatens the safe and stable operation of electric multiple units (EMUs). In order to investigate the primary factors affecting the electrical characteristics of the PC arc, this paper first reveals the mechanism of arc generation when EMUs leave the split-zone insulator according to the actual mechanical structure of the PC articulated split-zone insulator. Then, based on the Habedank black box arc model, considering the dynamic changes in arc length during the actual operation of EMUs, a numerical simulation model suitable for describing the PC articulated split-zone insulator arc is established. Furthermore, by comparing with existing research results, the effectiveness of the proposed model is verified. Next, a series of simulation experiments were conducted to analyze the influence of different operating parameters of the EMUs on the electrical characteristics of the PC arc. More importantly, the paper proposes using the entropy weight method to calculate the impact strength of different operating parameters of the EMUs on the arc duration time of the contact wire split-zone region. The research results of this paper can provide some technical references for reducing the erosion of the PC contact wire and slide caused by arcs when the EMUs pass through the split-zone insulator.},
	doi = {10.3390/en17163883},
	type = {JOUR}
}

@ARTICLE{10.20517/ces.2025.77,
	author = {Chen, Ji En and Wang, Xiao Kang and Song, Yang},
	title = {Research on arc length threshold of pantograph-catenary interaction leading to excessive disturbances in traction drive systems},
	journal = {Complex Engineering Systems},
	year = {2026},
	abstract = {With increasing train speeds, intensified vibrations in the pantograph-catenary (PC) system make separation between the pantograph and the contact wire - and the resulting arcing - more likely. These arcs degrade the current collection quality of high-speed trains, destabilize the traction drive system, and generate harmonics and electromagnetic interference that affect onboard communication equipment. This study investigates the impact of PC arcing at different train speeds on the traction system’s input voltage and rectifier-side direct-current (DC) voltage, and determines the corresponding acceptable arc length thresholds. An equivalent impedance model of the autotransformer traction network incorporating messenger wires and droppers is developed, together with a Habedank black-box arc model that accounts for the dynamic variations in dissipated power and voltage gradient with changing arc length. In parallel, an alternating current traction drive system model incorporating a pulse rectifier and traction motor is constructed, and its validity is verified by comparing simulation results with experimental data. Results indicate that within the allowable voltage disturbance range (input voltage 1,085-1,922 V; DC-side fluctuation ≤ 5%), the input voltage arc length threshold decreases from 0.887 cm to 0.826 cm as train speed increases from 200 km/h to 300 km/h, while the DC-side threshold drops from 1.28 cm to 0.75 cm. These findings reveal that higher speeds increase the sensitivity of the traction converter to voltage disturbances - identical arc lengths cause stronger voltage fluctuations. Moreover, for a given train speed, the input voltage arc length threshold remains higher than that of the rectifier-side DC voltage. ER -},
	doi = {10.20517/ces.2025.77},
	type = {JOUR}
}

@ARTICLE{10.3390/electronics12051262,
	author = {Jin, Meng Zhe and Wang, Shao Qian and Liu, Shang He and Fang, Qing Yuan and Liu, Wei Dong},
	title = {Statistical Study on the Time Characteristics of the Transient EMD Excitation Current from the Pantograph–Catenary Arcing Discharge},
	journal = {Electronics},
	year = {2023},
	keywords = {current pulse; electromagnetic disturbance; pantograph–catenary arcing; statical study ER -},
	abstract = {Electromagnetic disturbances (EMDs) resulting from arcing discharge between the pantograph and catenary pose a serious threat to the electromagnetic safety of electrified trains. The time characteristic of EMD excitation current has a significant impact on the generation mechanism and characteristics of electromagnetic emission from pantograph–catenary discharge, but there have been few studies on the topic. In this paper, a large sample of time-domain waveform parameters were collected through laboratory measurements considering the high randomness nature of the arcing discharge. The reference distributions of the waveform parameters were selected using the Kolmogorov–Smirnov test, and the probability density function parameters that vary with applied voltages and discharge gap spacings were examined. Then, a stochastic model for the derivation of the discharge current waveform was proposed based on statistical results using a modified double exponential function whose parameters can be derived from physical properties. Waveforms of the excitation currents representing different EMD severities were generated by adjusting the quantiles of the fitting distributions. The validity of the stochastic model was demonstrated by comparing the measured and simulated waveforms for both single pulses and pulse trains. The proposed method and generated waveforms can help recreate the electromagnetic environment of pantograph–catenary arcing.},
	doi = {10.3390/electronics12051262},
	type = {JOUR}
}

@ARTICLE{10.1049/els2.12043,
	author = {Zhou, Hong Yi and Duan, Fu Chuan and Liu, Zhi Gang and Chen, Long and Song, Yang and Zhang, Ye Xin},
	title = {Study on electric spark discharge between pantograph and catenary in electrified railway},
	journal = {IET Electrical Systems in Transportation},
	year = {2022},
	keywords = {electric spark discharge; electrified railway; pantograph-catenary electrical contact; traction power ER -},
	abstract = {Abstract The electric spark caused by pantograph‐catenary (PC) electrical contact failure happens frequently, it is a kind of arcing phenomenon which can severely affect the current collection of PC. The theoretical analysis and modelling of PC electric spark are tried. First, the contact spots between PC and their temperature rise are analysed and derived based on the classical electrical contact theory, respectively. The mechanism of spark discharge is revealed through the analysis of PC voltage difference, and the spark discharge model is proposed combining with the spot temperature rise formula and spark discharge mechanism. Then, in order to obtain some key parameters in an electric spark discharge model, such as contact force and contact current, the structure model of PC and the circuit model of vehicle‐grid are established for the calculation of the spark rate in PC. Finally, the spark rate is calculated and analysed under the different parameters in PC system. The calculation results are verified by the experiment results. Through the presentation of the correlation of electric spark discharge and factors, such as contact force, contact current and material of PC, this study can support the assessment of electrical contact quality in the PC system in future study.},
	doi = {10.1049/els2.12043},
	type = {JOUR}
}

@ARTICLE{10.3390/infrastructures11010017,
	author = {Pan, Li Ke and Wang, Xiao Kang and Yuan, Yuan and Xing, Tong and Chen, Li Ming},
	title = {Transient Arcing Characteristics of the Pantograph–Catenary System in Electrical Sectioning Overlaps},
	journal = {Infrastructures},
	year = {2026},
	abstract = {Transient arcing often occurs as an electric locomotive traverses an electrical sectioning overlap (ESO), deteriorating current collection stability and reducing the durability of the pantograph–catenary (PC) system. In this study, the formation mechanism and electrical evolution characteristics of transient arcing in the ESO region are investigated through theoretical analysis and numerical simulations. First, based on the dynamic motion of the locomotive passing through the ESO, the transient arcing mechanism of the ESO is clarified, and the plasma characteristics of the arc are described. Then, the electromagnetic, airflow, and thermal field interactions within the PC contact gap during arc ignition are analyzed. A Multiphysics coupled PC arc model is developed, incorporating aerodynamic, electromagnetic, and heat transfer effects. Subsequently, finite element meshing and boundary conditions are applied to simulate the transient evolution of the ESO arc. Finally, the transient arcing characteristics of the ESO are analyzed. The results indicate that the current density is highly concentrated at the initial arcing stage and gradually forms an axially symmetric conductive channel (approximately 107 A/m2), which shifts upward as the contact gap increases. Moreover, due to the geometric discontinuity of the ESO, a strong localized electric field develops near the wire edge, leading to arc root migration and reignition. ER -},
	doi = {10.3390/infrastructures11010017},
	type = {JOUR}
}

@ARTICLE{10.3390/su17146285,
	author = {Yu, Xiao Ying and Song, Li Ying and Su, Yang and Yang, Jun Rui and Lu, Xiao Juan and Wei, Cai Zhuo and Cheng, Yong Jia and Liu, Yi Xiao},
	title = {Electrical Characteristics of the Pantograph-Catenary Arc in Urban Rail Transit Under Different Air Pressure Conditions},
	journal = {Sustainability},
	year = {2025},
	abstract = {Nowadays, urban rail transit is expanding towards high-elevation zones, and the effect of the low air pressure environment on the pantograph-catenary system is becoming increasingly prominent. As a key indicator for evaluating the electrical contact performance of a pantograph-catenary system, research on the electrical characteristics of the pantograph-catenary arc is of great significance. For this reason, this paper established a plasma mathematical model applicable to the arc of the urban rail transit bow network based on the theory of magnetohydrodynamics. The mathematical model of the pantograph-catenary arc was used to set the relevant initial conditions. Based on COMSOL Multiphysics finite element simulation software, this study developed a multi-physics simulation model of the pantograph-catenary arc and systematically analysed its voltage characteristics and current density distribution under varying air pressure conditions. The results showed that as the air pressure decreases, the potential at the axial points declines, the pressure drop across the arc poles becomes more pronounced, and the current density decreases accordingly. This study provides theoretical and technical support for optimizing the design of and promoting the sustainable development of urban rail transit pantograph-catenary systems in high-altitude areas. ER -},
	doi = {10.3390/su17146285},
	type = {JOUR}
}

@ARTICLE{10.3390/en17071512,
	author = {Huang, Ke and Su, Dong Dong},
	title = {Extended Pantograph–Catenary Arc Modeling and an Analysis of the Vehicular-Grounding Electromagnetic Transients of Electric Multiple Units},
	journal = {Energies},
	year = {2024},
	abstract = {As the operating speed of electric multiple units (EMUs) in high-speed railways increases, pantograph–catenary (PC) detachment arcing occurs frequently. The resulting vehicular-grounding electromagnetic transients are related to the dynamic characteristics of the arc length. During large detachment, the processes of arc extinction and arc reignition may occur, resulting in more severe train body (TB) over-voltages and adverse effects on some vehicular electronic devices. As an extension of the previous works, this paper aims to establish a suitable PC arc model to examine the TB transient voltages. To begin with, the arc length dynamic characteristics are reasonably analyzed to deduce the relationship between the detachment distance and the arc length via the chain arc model. Then, the dynamic characteristics of the arc length are introduced, and an arc modeling scheme is proposed to elaborate the vehicle-grid electric power model for EMUs encountering various arcing scenarios. Based on this, the transient over-voltages are analyzed, accounting for both the arc extinction and arc reignition, as well as the mutual influences of multiple detachments in a short time. The influential factors, including arc length characteristics, phase angle, excitation inductance, and grounding parameters, are also involved in the performed analyses. ER -},
	doi = {10.3390/en17071512},
	type = {JOUR}
}
